### Configure Date Field Display in Payload CMS Collection

Source: https://github.com/payloadcms/payload/blob/main/docs/fields/date.mdx

This snippet demonstrates how to configure date fields within a Payload CMS collection to display only specific parts of a date, such as day, time, or month. It uses `pickerAppearance` and `displayFormat` within the `admin.date` property to control the UI and formatting of the date picker.

```ts
import type { CollectionConfig } from 'payload'

export const ExampleCollection: CollectionConfig = {
  slug: 'example-collection',
  fields: [
    {
      name: 'dateOnly',
      type: 'date',
      admin: {
        date: {
          pickerAppearance: 'dayOnly',
          displayFormat: 'd MMM yyy',
        },
      },
    },
    {
      name: 'timeOnly',
      type: 'date',
      admin: {
        date: {
          pickerAppearance: 'timeOnly',
          displayFormat: 'h:mm:ss a',
        },
      },
    },
    {
      name: 'monthOnly',
      type: 'date',
      admin: {
        date: {
          pickerAppearance: 'monthOnly',
          displayFormat: 'MMMM yyyy',
        },
      },
    },
  ],
}
```

