### Configure Payload CMS Auth Collection (TypeScript)

Source: https://github.com/payloadcms/payload/blob/main/tools/claude-plugin/skills/payload/reference/COLLECTIONS.md

Sets up an authenticated 'Users' collection in Payload CMS, configuring authentication options like token expiration, email verification, maximum login attempts, and lock time. It also enables API key usage and defines user-specific fields such as roles (with `hasMany` and `saveToJWT`) and name.

```typescript
export const Users: CollectionConfig = {
  slug: 'users',
  auth: {
    tokenExpiration: 7200, // 2 hours
    verify: true,
    maxLoginAttempts: 5,
    lockTime: 600000, // 10 minutes
    useAPIKey: true,
  },
  admin: {
    useAsTitle: 'email',
  },
  fields: [
    {
      name: 'roles',
      type: 'select',
      hasMany: true,
      options: ['admin', 'editor', 'user'],
      required: true,
      defaultValue: ['user'],
      saveToJWT: true,
    },
    {
      name: 'name',
      type: 'text',
      required: true,
    }
  ]
}
```

